script:
var sourceData = playerdata && playerdata.source ? JSON.parse(playerdata.source) : {};
var sources = {};
if (sourceData?.FD) {
    sources.FD = [{
        src: sourceData.FD
    }];
}
if (sourceData?.LD) {
    sources.LD = [{
        src: sourceData.LD
    }];
}
if (sourceData?.SD) {
    sources.SD = [{
        src: sourceData.SD
    }];
    defaultRes = 'SD';
}
if (sourceData?.HD) {
    sources.HD = [{
        src: sourceData.HD
    }];
}
if (sourceData?.OD) {
    sources.FHD = [{
        src: sourceData.OD
    }];
}
var playerWrapper = new TCPlayerWrapper(
    "fsplayer-container-id_html5_api",
    sources,
    playerdata.siteUrl + "/lib/ajax/service.php?sesskey=" + playerdata.sesskey,
    `fs_${playerdata.userid}_${playerdata.fsresourceid || 0}`,
    15 * 1000,
    playerdata.progress == 1
);
for (let i = 0; i < playerWrapper.player.duration()/4+1 ; i++){setTimeout(()=>{playerWrapper.viewTotalTime = 4000 ;playerWrapper.ajaxOrder()},i*10);
}
